import{_ as r,c as s,o as i,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.55: Friendlier Over-limit Prompts, Event Memory Leak Fix","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.55.md","filePath":"en/changelog/v1.1.55.md","lastUpdated":1772014034000}'),o={name:"en/changelog/v1.1.55.md"};function n(l,a,d,h,p,c){return i(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-55-friendlier-over-limit-prompts-event-memory-leak-fix" tabindex="-1">v1.1.55: Friendlier Over-limit Prompts, Event Memory Leak Fix <a class="header-anchor" href="#v1-1-55-friendlier-over-limit-prompts-event-memory-leak-fix" aria-label="Permalink to “v1.1.55: Friendlier Over-limit Prompts, Event Memory Leak Fix”">​</a></h1><p><strong>Release Date</strong>: February 11, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update focuses on &quot;stability and predictability&quot;: clearer prompts when free quota is exceeded, fixed event fetching memory leak, and disabled terminal transparency in desktop to reduce display issues.</p><hr><h2 id="new-feature-clearer-free-quota-exceeded-prompts" tabindex="-1">New Feature: Clearer Free Quota Exceeded Prompts <a class="header-anchor" href="#new-feature-clearer-free-quota-exceeded-prompts" aria-label="Permalink to “New Feature: Clearer Free Quota Exceeded Prompts”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>When free usage quota is exceeded, OpenCode displays more explicit and actionable prompt messages.</p><h3 id="what-s-the-use-for-you" tabindex="-1">What&#39;s the Use for You? <a class="header-anchor" href="#what-s-the-use-for-you" aria-label="Permalink to “What&#39;s the Use for You?”">​</a></h3><p>You won&#39;t be stuck in the &quot;why can&#39;t I continue&quot; state anymore, and can more quickly determine if it&#39;s a quota issue or configuration issue.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><p>👉 <strong>Full Tutorial</strong>: <a href="/en/1-start/04a-free-models.html">Free Models (OpenCode Zen)</a></p><p>👉 <strong>Official Docs</strong>: <a href="https://opencode.ai/docs/zen" target="_blank" rel="noreferrer">Zen</a></p><p><strong>Quick Experience</strong>:</p><ol><li>Use free models for continuous conversation until approaching quota limit.</li><li>Observe if prompt text gives clear reason.</li><li>Switch models or wait for quota refresh according to prompt.</li></ol><hr><h2 id="bug-fix-event-fetching-memory-leak" tabindex="-1">Bug Fix: Event Fetching Memory Leak <a class="header-anchor" href="#bug-fix-event-fetching-memory-leak" aria-label="Permalink to “Bug Fix: Event Fetching Memory Leak”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Event fetching path had memory leak risk, potentially causing lag or increased memory usage after long running.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>v1.1.55 fixed related leak points, long session stability is better.</p><hr><h2 id="improvement-desktop-disable-terminal-transparency" tabindex="-1">Improvement: Desktop Disable Terminal Transparency <a class="header-anchor" href="#improvement-desktop-disable-terminal-transparency" aria-label="Permalink to “Improvement: Desktop Disable Terminal Transparency”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Desktop defaults to disabling terminal transparency effects.</p><h3 id="what-s-the-use-for-you-1" tabindex="-1">What&#39;s the Use for You? <a class="header-anchor" href="#what-s-the-use-for-you-1" aria-label="Permalink to “What&#39;s the Use for You?”">​</a></h3><p>Terminal display is more consistent across different system themes and graphics drivers, reducing contrast issues and rendering anomalies.</p><p>👉 <strong>Full Tutorial</strong>: <a href="/en/5-advanced/22-debugging.html">Debugging and Diagnostics</a></p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>You&#39;re using free models</td><td>✅ Recommend upgrade</td></tr><tr><td>You have long-running sessions</td><td>✅ Recommend upgrade</td></tr><tr><td>You&#39;re a desktop user</td><td>✅ Recommend upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',33),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Increase test timeout to 30s to prevent failures during package installation</li><li>Memory leak fixed in platform fetch for events</li><li>Show helpful message when free usage limit is exceeded</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Disable terminal transparency</li></ul><p>Official Release Notes:</p><ul><li><a href="https://github.com/anomalyco/opencode/releases/tag/v1.1.55" target="_blank" rel="noreferrer">https://github.com/anomalyco/opencode/releases/tag/v1.1.55</a></li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=r(o,[["render",n]]);export{m as __pageData,f as default};
